  ('judicial-f0899a01-moex-00534', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '關於罪刑法定原則，下列敘述何者錯誤？', '["刑法所規定的犯罪要件與法律效果應力求具體明確", "沒收適用裁判時之法律", "強制工作並非刑罰，故無須受到罪刑法定原則之拘束", "習慣法不得作為論罪科刑之依據"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:47+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
